Prolog:
sDimension = Trim(pDimension);
sElement = Trim(pElement);
sRoot = Trim(pRoot);
sElementType = Upper(Trim(pElementType));

If(sDimension @= '');
  ProcessBreak;
EndIf;
If(sElement @= '');
  ProcessBreak;
EndIf;
If(sRoot @= '');
  ProcessBreak;
EndIf;
If(sElementType @= '');
  sElementType = 'N';
EndIf;

If(DimensionExists(sDimension) = 0);
  ProcessBreak;
EndIf;
If(DimensionElementExists(sDimension, sRoot) = 0);
  ProcessBreak;
EndIf;

If(DimensionElementExists(sDimension, sElement) = 0);
  DimensionElementInsert(sDimension, '', sElement, sElementType);
  If(DimensionElementExists(sDimension, sElement) = 0);
    ProcessBreak;
  EndIf;
EndIf;

If(ELISPAR(sDimension, sRoot, sElement) = 0);
  DimensionElementComponentAdd(sDimension, sRoot, sElement, 1);
EndIf;
